INSERT INTO public.chateaux (id, nom, slug, region, departement, ville, accroche, siecle, style, distance_paris, distance_paris_label, urgence, coordonnees_lat, coordonnees_lng, histoire, description, region_narrative, region_histoire, chiffres_cles, images, video_background_youtube_id, prop_nom, prop_depuis, prop_initiale, prop_nom_affiche, prop_portrait, prop_citation, prop_description, est_la_une, is_demo_mock, note_sur_5, nb_avis, date_disponible, couleur_theme, accent_theme, petit_dejeuner, parking, wifi, animaux) VALUES
  ('1835a34d-9680-5a79-8eb4-313e3932c782', 'Château de Vaux-le-Vicomte', 'vaux-le-vicomte', 'Île-de-France', 'Seine-et-Marne', 'Maincy', 'Le château qui inspira Versailles, le temps d''une nuit', 'XVIIe', 'Baroque classique', 45, '55 km · 45 min', 'J-7', 48.5681, 2.7157, 'Demeure légendaire de Nicolas Fouquet, surintendant des finances de Louis XIV, Vaux-le-Vicomte fut érigé entre 1658 et 1661. Sa magnificence provoqua la jalousie du Roi-Soleil, qui fit arrêter Fouquet peu après la fête d''inauguration. Le château devint alors le modèle sur lequel fut conçu Versailles. Ses jardins à la française, dessinés par André Le Nôtre, ses appartements d''apparat peints par Charles Le Brun, et son architecture signée Louis Le Vau composent un ensemble d''une cohérence artistique rare.', 'Demeure légendaire de Nicolas Fouquet, Vaux-le-Vicomte incarne le faste du Grand Siècle. Ses jardins à la française dessinés par Le Nôtre, ses appartements d''apparat et ses cuisines historiques composent un écrin incomparable pour une nuit d''exception.', 'L''Île-de-France réunit les grandes résidences royales et nobiliaires de France. Vaux-le-Vicomte, en Seine-et-Marne, s''inscrit dans cette tradition de proximité avec le pouvoir. Le domaine, aux portes de la Brie, illustre l''art des jardins à la française au XVIIe siècle.', 'La Seine-et-Marne fut historiquement le pays de Brie, terre fertile et prospère sous l''Ancien Régime. Sa proximité avec Paris et la Cour y attira l''aristocratie et les officiers du roi. Châteaux de Fontainebleau, Vaux-le-Vicomte, Champs-sur-Marne et Blandy-les-Tours témoignent de ce passé d''apparat et de pouvoir.', NULL, ARRAY['https://images.unsplash.com/photo-1562602833-0f4ab2fc46e3?w=1200&q=80','https://images.unsplash.com/photo-1571896349842-33c89424de2d?w=1200&q=80','https://images.unsplash.com/photo-1566073771259-6a8506099945?w=1200&q=80']::text[], NULL, 'Famille de Vogüé', '1875', 'F', 'de Vogüé', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&q=80', 'Vaux-le-Vicomte n''est pas un musée, c''est une maison vivante. Chaque soir aux chandelles, nous voyons des yeux s''émerveiller — c''est pour cela que nous continuons.', 'La famille de Vogüé veille sur Vaux-le-Vicomte depuis cinq générations. Héritiers d''Alfred Sommier qui sauva le château de la ruine en 1875, ils ont fait le choix de l''ouvrir au monde tout en préservant son caractère intimement privé.', false, true, NULL, 0, NULL, '#1a2d5a', '#c8973e', false, true, true, false),
  ('471c00ee-8b12-5943-8e79-dddf07959a82', 'Château de Pierrefonds', 'pierrefonds', 'Hauts-de-France', 'Oise', 'Pierrefonds', 'Une forteresse médiévale sortie tout droit des légendes arthuriennes', 'XIIe–XIXe', 'Médiéval restauré', 70, '85 km · 1h10', 'J-10', 49.3442, 2.9797, 'Édifié au XIIe siècle, le château de Pierrefonds fut rasé sur ordre de Louis XIV en 1617. Napoléon III en fit l''acquisition en 1813 pour la somme symbolique de 2 500 francs, puis confia sa restauration à Eugène Viollet-le-Duc entre 1857 et 1885. Ce dernier ne se contenta pas de restaurer mais réinventa une forteresse médiévale idéale, enrichie d''une iconographie arthurienne et royale qui en fait un château de rêve autant qu''un monument historique.', 'Restauré par Viollet-le-Duc pour Napoléon III, Pierrefonds est l''une des plus spectaculaires forteresses médiévales d''Europe. Ses tours majestueuses, ses douves et ses salles d''armes transportent instantanément dans un autre siècle.', 'Les Hauts-de-France, autour de Compiègne, sont une terre de forêts royales et de châteaux où l''histoire s''est jouée à plusieurs reprises. Pierrefonds, dans l''Oise, illustre la fascination du XIXe siècle pour le Moyen Âge réinventé par Viollet-le-Duc.', 'L''Oise fut au cœur du royaume capétien, terre des seigneurs de Valois et résidence des rois de France à Compiègne. Forêts profondes, abbayes médiévales et palais impériaux y composent un paysage patrimonial dense, marqué aussi par les deux guerres mondiales — la signature de l''Armistice de 1918 s''y est tenue.', NULL, ARRAY['https://images.unsplash.com/photo-1533154683836-84ea7a0bc310?w=1200&q=80']::text[], NULL, 'Centre des Monuments Nationaux', '1885', 'C', 'Centre des Monuments Nationaux', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=400&q=80', 'Pierrefonds est l''œuvre d''un génie et d''un empereur. Notre mission est de faire vivre ce rêve de pierre pour les générations futures.', 'Propriété de l''État depuis Napoléon III, Pierrefonds est géré par le Centre des Monuments Nationaux qui a ouvert une aile résidentielle d''exception permettant de dormir dans la forteresse même.', false, true, NULL, 0, NULL, '#2c1810', '#c8973e', false, true, true, true),
  ('e2e456fe-231c-54c0-8ae8-18154104e827', 'Château de Chantilly', 'chantilly', 'Hauts-de-France', 'Oise', 'Chantilly', 'Le grand domaine des Condé, entre forêt, hippodrome et musée', 'XVIe–XIXe', 'Renaissance & Classique', 35, '48 km · 35 min', 'J-15', 49.1936, 2.4847, 'Le domaine de Chantilly appartint successivement aux plus grandes familles de France. Anne de Montmorency, connétable de France, y fit édifier le Grand Château au XVIe siècle. Le Grand Condé, vainqueur de Rocroi, en fit une résidence fastueuse confiée à Le Nôtre pour les jardins et Molière pour les divertissements. Le duc d''Aumale, fils de Louis-Philippe, légua l''ensemble à l''Institut de France avec sa collection de peintures, aujourd''hui l''une des plus importantes de France après le Louvre.', 'Entouré de douves et de jardins à la française, le Château de Chantilly abrite l''un des plus beaux musées de peinture de France. L''hippodrome, la forêt et les Grandes Écuries composent un domaine d''une richesse incomparable.', 'À une heure de Paris, la plaine cantilienne ouvre les Hauts-de-France sur un paysage de forêts royales et de grands domaines. Chantilly, terre des Condé puis du duc d''Aumale, abrite l''un des plus importants ensembles patrimoniaux français au nord de la capitale.', 'Le pays de Chantilly fut longtemps le territoire des Montmorency et des Condé, princes du sang et grands soldats du royaume. Le duc d''Aumale, fils de Louis-Philippe, légua le domaine à l''Institut de France en 1886 avec sa collection de peintures, l''une des plus importantes en France après celle du Louvre.', NULL, ARRAY['https://images.unsplash.com/photo-1659526062822-72f35fedff25?w=1200&q=80','https://images.unsplash.com/photo-1566073771259-6a8506099945?w=1200&q=80']::text[], NULL, 'Institut de France', '1886', 'I', 'Institut de France', 'https://images.unsplash.com/photo-1560250097-0dc005d9af94?w=400&q=80', 'Le duc d''Aumale nous a légué non seulement un château, mais une vision de la France à son apogée. Nous en sommes les gardiens humbles et fiers.', 'L''Institut de France, gardien du domaine depuis le legs du duc d''Aumale en 1886, a ouvert les Grandes Écuries en hébergement de prestige. Une façon unique de dormir au cœur d''un des plus grands domaines de France.', false, true, NULL, 0, NULL, '#1a3a2a', '#c8973e', false, true, true, false),
  ('1aa33001-b80e-5447-8f00-4d251072be67', 'Château de Fontainebleau', 'fontainebleau', 'Île-de-France', 'Seine-et-Marne', 'Fontainebleau', 'La demeure de trente rois de France, au cœur de la forêt', 'XVIe', 'Renaissance royale', 50, '65 km · 50 min', 'J-7', 48.4025, 2.7017, 'Fontainebleau est la seule résidence royale française habitée sans interruption pendant huit siècles, de Saint Louis à Napoléon III. François Ier en fit une Renaissance à la française en y invitant les meilleurs artistes italiens — le Rosso Fiorentino et le Primatice — créant ainsi la première École de Fontainebleau. Napoléon Ier y signa son abdication le 11 avril 1814, dans le Salon Rouge, épisode entré dans l''histoire comme les Adieux de Fontainebleau.', 'Résidence favorite des rois de France pendant huit siècles, Fontainebleau est un palais vivant, entouré d''une forêt de 25 000 hectares idéale pour l''escalade, l''équitation et les promenades au grand air.', 'La forêt de Fontainebleau, vaste de 25 000 hectares, forme un écrin sauvage rare aux portes de l''Île-de-France. Le château, résidence favorite de trente rois de France, s''y déploie depuis le XIIe siècle au cœur des chaos de grès et des chemins forestiers.', 'Fontainebleau fut la seule résidence royale française habitée sans interruption pendant huit siècles, de Saint Louis à Napoléon III. François Ier y créa la première École de Fontainebleau en invitant les artistes italiens du XVIe siècle. Napoléon Ier y signa son abdication en 1814 — les Adieux entrés dans la légende française.', NULL, ARRAY['https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=1200&q=80','https://images.unsplash.com/photo-1578683010236-d716f9a3f461?w=1200&q=80','https://images.unsplash.com/photo-1566073771259-6a8506099945?w=1200&q=80']::text[], NULL, 'République Française — CMN', '1793', 'R', 'République Française — CMN', 'https://images.unsplash.com/photo-1519085360753-af0119f7cbe7?w=400&q=80', 'Fontainebleau n''appartient pas à la France — c''est la France elle-même, condensée en pierre, en or et en forêt.', 'Propriété nationale depuis la Révolution, Fontainebleau est géré par le Centre des Monuments Nationaux. Une aile privée a été ouverte aux hôtes de marque, permettant de vivre dans les murs où trente rois ont résidé.', false, true, NULL, 0, NULL, '#1a2d1a', '#c8973e', false, true, true, true),
  ('49be38ea-2e0f-5063-840b-ff44680a5654', 'Château de La Ferté-Saint-Aubin', 'ferte-saint-aubin', 'Centre-Val de Loire', 'Loiret', 'La Ferté-Saint-Aubin', 'Un château habité, chaleureux, au cœur de la Sologne', 'XVIIe', 'Classique ligérien', 90, '155 km · 1h30', 'J-10', 47.7197, 1.9558, 'La Ferté-Saint-Aubin est l''un des rares châteaux de France encore habité et transmis dans la même famille depuis le XVIIe siècle. Édifié pour Henri de Saint-Nectaire, maréchal de France, il conserve son mobilier d''origine et ses cuisines d''époque intactes. La Sologne environnante, avec ses étangs, ses forêts de pins et ses domaines de chasse, forme le cadre idéal de cette immersion dans une aristocratie rurale authentique, loin des fastes versaillais.', 'Rare château encore habité et transmis dans la même famille depuis des siècles, La Ferté-Saint-Aubin offre une expérience authentique et intimiste : grands appartements, cuisines d''époque, parc giboyeux et étangs de Sologne.', 'Le Loiret, en lisière nord du Centre-Val de Loire, ouvre les paysages de Sologne — étangs, forêts de pins, manoirs de chasse. La Ferté-Saint-Aubin s''inscrit dans cette tradition d''aristocratie rurale française, à mi-chemin entre Orléans et les grands châteaux ligériens du Val de Loire.', 'Le Centre-Val de Loire est la terre des grands châteaux royaux et nobiliaires de la Renaissance — Chambord, Cheverny, Chenonceau, Blois. Le Val de Loire est inscrit au patrimoine mondial de l''UNESCO depuis 2000. La Sologne au nord, ancienne réserve de chasse des rois et de la noblesse, conserve ses étangs, ses forêts et ses traditions cynégétiques.', NULL, ARRAY['https://images.unsplash.com/photo-1564501049412-61c2a3083791?w=1200&q=80','https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=1200&q=80']::text[], NULL, 'Famille de Jouffroy-Gonsans', '1840', 'F', 'de Jouffroy-Gonsans', 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=400&q=80', 'Mon arrière-grand-père aurait pu vendre. Mon grand-père aurait pu transformer en hôtel. Nous avons choisi de rester. Ce château vit parce que nous y vivons — et nos hôtes le sentent dès qu''ils franchissent le pont-levis.', 'Cinq générations. Une seule famille. La famille de Jouffroy-Gonsans n''a jamais cédé à la tentation de la vente ni à celle de la chaîne hôtelière. Ils habitent La Ferté à l''année, reçoivent leurs hôtes à leur table et transmettent, saison après saison, l''art de vivre d''une aristocratie rurale française qui n''existe plus nulle part ailleurs avec cette authenticité.', false, true, NULL, 0, NULL, '#2d1f0e', '#c8973e', false, true, false, true),
  ('5b612841-ab26-5cbd-8b8a-deb8607d6dc8', 'Château de Pierreclos', 'pierreclos', 'Bourgogne-Franche-Comté', 'Saône-et-Loire', 'Pierreclos', 'Huit siècles de pierre, douze hectares de vignes, une famille — le château le plus vivant de Bourgogne', 'XIIe–XVe', 'Médiéval bourguignon', 180, '370 km · 3h', 'J-15', 46.3764, 4.6897, 'Depuis le XIIe siècle, le château de Pierreclos domine en silence les vignes du Mâconnais. Ses murs épais d''un mètre ont traversé les guerres de Religion, la Révolution, deux conflits mondiaux — sans jamais changer de nature. C''est un château de travail autant que de prestige : la famille Goyard y cultive ses 12 hectares de vignes en agriculture raisonnée depuis quatre générations, produisant un Mâcon Villages que les amateurs s''arrachent. Lamartine, enfant du pays, venait s''y ressourcer et y puisa l''inspiration de ses plus belles Méditations. Aujourd''hui comme hier, Pierreclos est un château qui vit — qui produit, qui reçoit, qui transmet. Pas un monument figé dans l''ambre, mais une demeure où chaque saison a son rythme, ses vendanges, ses lumières.', 'Juché sur les hauteurs du Mâconnais, entre Pouilly-Fuissé et Cluny, le château de Pierreclos est à la fois une forteresse médiévale du XIIe siècle, un domaine viticole en activité et une maison de famille habitée depuis des générations. La famille Goyard vous reçoit à leur table, vous emmène dans leurs vignes et vous ouvre leur cave du Moyen Âge. À 3h de Paris, c''est la Bourgogne dans son état le plus pur — celle d''avant les guides et les circuits touristiques.', 'Le Mâconnais, au sud de la Bourgogne, ouvre les coteaux des grands blancs de chardonnay — Pouilly-Fuissé, Mâcon Villages, Saint-Véran. Pierreclos s''élève au cœur de ce paysage viticole, sur les hauteurs qui dominent la Saône et marquent le début des reliefs du Beaujolais.', 'La Bourgogne fut au Moyen Âge l''un des duchés les plus puissants d''Europe occidentale, rivale du royaume de France. Cluny y rayonna comme premier ordre monastique de la chrétienté. Le Mâconnais, terre frontière entre Bourgogne et Lyonnais, vit naître Lamartine et conserve un patrimoine roman et viticole exceptionnel — les Climats du vignoble sont classés à l''UNESCO.', NULL, ARRAY['https://images.unsplash.com/photo-1595526114035-0d45ed16cfbf?w=1200&q=80','https://images.unsplash.com/photo-1760372057956-d20c2195c7a2?w=1200&q=80','https://images.unsplash.com/photo-1533105079780-92b9be482077?w=1200&q=80']::text[], NULL, 'Famille Goyard', '1920', 'F', 'Goyard', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?w=400&q=80', 'Mon grand-père vendangeait ces vignes à la main. Je fais pareil. Et quand nos hôtes descendent à la cave avec moi le soir, ils comprennent pourquoi on ne vendra jamais — ni le château, ni les vignes.', 'Quatre générations de Goyard ont cultivé ces vignes et habité ces murs sans jamais envisager autre chose. Vignerons le matin, châtelains le soir — ils incarnent un art de vivre bourguignon qui ne se trouve plus dans les brochures. Leurs hôtes ne sont pas des touristes : ce sont des gens à qui ils choisissent d''ouvrir leur maison, leur cave et leur table.', false, true, NULL, 0, NULL, '#2d1a0e', '#c8973e', false, true, true, false),
  ('35015d71-5591-570c-8023-cc077d981cd4', 'Château des Briottières', 'les-briottieres', 'Pays de la Loire', 'Maine-et-Loire', 'Champigné', 'Sept générations d’une même famille, cinquante hectares d’Anjou, une table aux chandelles chaque soir', 'XVIIIe siècle', 'Demeure familiale · Art de vivre anjouvin', 135, '2h15 de Paris', 'J-10', 47.6833, -0.5333, 'Nées au coeur de l''Anjou à la fin du Moyen Âge, les Briottières ont traversé les siècles entre nobles alliances et bâtisseurs passionnés. La chapelle Saint-Bonaventure, édifiée en 1528, en témoigne. Acquis au XIXe siècle par Alfred de Mieulle, aïeul de l''actuel propriétaire, le Château devient une élégante demeure estivale entourée d''un parc à l''anglaise de 50 hectares. Madame de Staël l''a aimée. George Sand et Chopin y ont séjourné. Depuis sept générations, chaque famille y a cultivé un art de vivre singulier.', 'Au coeur de l''Anjou, dans un parc à l''anglaise de 50 hectares dessiné par le paysagiste Châtelain, le Château des Briottières est dans la même famille depuis sept générations. Arnaud et Madeleine de Valbray y accueillent les voyageurs du monde entier comme à la maison — promenades dans le parc arboré, sieste au bord de la piscine, dîner aux chandelles. Ici, le luxe se mesure en silence, en espace et en beauté.', 'L''Anjou est l''une des provinces les plus douces de France — ni la brutalité de l''Atlantique, ni la rigueur continentale. Un bocage généreux, des châteaux discrets, des vignes qui donnent le Savennières et le Layon. Les Briottières s''inscrivent dans ce paysage comme une évidence : une demeure qui n''a jamais cherché à impressionner, seulement à accueillir.', 'Le Maine-et-Loire fut longtemps le cœur du royaume des Plantagenets. Angers, capitale de l’Anjou, vit naître Henri II d’Angleterre et le roi René, dernier duc d’Anjou, ce prince lettré qui fit de sa cour l’une des plus brillantes d’Europe. La Loire, classée au patrimoine mondial de l’Unesco, borde le département au sud. L’Anjou bleu au nord — où se trouvent les Briottières — est un pays de bocage, de forêts et d’étangs, plus discret que la Loire mais tout aussi envoutant.', NULL, ARRAY['/bri-1.avif','/bri-2.avif','https://images.unsplash.com/photo-1566073771259-6a8506099945?w=1200&q=80']::text[], NULL, 'Arnaud & Madeleine de Valbray', '2010', 'A', 'Arnaud & Madeleine de Valbray', '/bri-arnaud.avif', 'Dans la même famille depuis sept générations. Ici, le luxe se mesure en silence, en espace et en beauté.', 'Arnaud de Valbray a grandi dans ces murs. Avec Madeleine, ils perpétuent le flambeau de François et Hedwige de Valbray qui firent renaître la maison en 1979. Ils reçoivent leurs hôtes comme des invités — chaleur d''une maison de famille, discrétion d''un hôtel confidentiel, fierté d''une histoire transmise depuis sept générations.', true, false, NULL, 0, NULL, '#1a0e05', '#C09840', false, true, true, true),
  ('b9e0f516-d575-5f55-804e-f66187825cd0', 'Château du Blanc Buisson', 'blanc-buisson', 'Normandie', 'Eure', 'Rugles', 'Sept siècles d’histoire, trois familles, des douves, un donjon — le plus discret des châteaux normands', 'XIIIe siècle', 'Château médiéval · Normandie historique', 120, '2h de Paris', 'J-15', 48.9167, 0.7333, 'En 1290, sous le règne de Philippe le Bel, Colinet Lecomte fait édifier le Blanc Buisson pour protéger les paysans du Pays d’Ouche contre les brigands. Sept siècles ont passé. Le château n’a appartenu qu’à trois familles, transmis presque toujours par mariage ou héritage. Au XIVe siècle, les troupes du roi Jean II assiègent la demeure et détruisent son premier étage. Il faudra attendre le XVe siècle pour que Marie Colinet Le Conte et Jean II du Merle le reconstruisent, mélant douves, tourelles, pont-levis et échauguéttes dans un style à la charnière du Góthique et de la Renaissance. En 1801, vendu pour la première et unique fois, il entre dans la famille Pillons de Saint-Philbert, ancêtres des propriétaires actuels. Aujourd’hui, Maïté et Éric de la Fresnaye l’habitent, le restaurent et l’animent avec une passion intègre. Le château n’est pas un musée : c’est une maison vivante, où chaque pièce semble habitée, comme si le temps s’y était arrêté.', 'Au cœur du Pays d’Ouche normand, niché dans un parc de 8 hectares classé pour ses essences rares, le Château du Blanc Buisson est un chef-d''œuvre de l’architecture féodale tardive. Douves intégrales, pont-levis, donjon carré, tourelles de garde — tout est intact depuis 1290. Maïté et Éric de la Fresnaye y accueillent leurs hôtes dans la Suite du Donjon et dans La Réserve, avec la chaleur d’une maison de famille.', 'Le Pays d’Ouche est l’une des contrées les plus secrets de Normandie. Ni côtière ni touristique, cette terre de bocages, de forêts denses et d’étangs silencieux s’étend entre l’Eure et l’Orne, loin des circuits battus. On y croise des abbayes cisterciennes, des manoirs de brique et de silex, des villages où le temps semble suspendu. Le Blanc Buisson s’inscrit dans ce paysage comme il y a sept siècles : discret, intact, vivant.', 'La Normandie est l’une des provinces les plus chargées d’histoire de France. Conquise par les Vikings au IXe siècle, elle devient le duché qui donnera Guillaume le Conquérant et changera le destin de l’Angleterre en 1066. Le Pays d’Ouche, lui, vécut au rythme des guerres entre capétiens et plantagenêts, des chevauchées anglaises pendant la Guerre de Cent Ans, et des reconstructions patientes qui suivirent. C’est dans ce contexte que le Blanc Buisson fut assiégé au XIVe siècle par les troupes du roi Jean II — et que ses propriétaires le reconstruisirent, pierre par pierre, tel qu’il se dresse encore aujourd’hui.', NULL, ARRAY['/bb-p1.avif','/bb-p2.avif','/bb-p3.avif']::text[], 'JQ9m51Bl900', 'Maïté & Éric de la Fresnaye', '2014', 'M', 'Maïté & Éric de la Fresnaye', '/bb-eric2.jpg', 'Ce château n’a appartenu qu’à trois familles en sept siècles. Quand vous venez ici, vous sentez que les murs ont une mémoire. Notre rôle est de la garder vivante.', 'Éric de la Fresnaye a hérité du Blanc Buisson en 2014. Avec Maïté, ils ont engagé une restauration minutieuse et décidé d’ouvrir le château aux séminaires, mariages et séjours — non par nécessité commerciale, mais par conviction patrimoniale. Ils reçoivent leurs hôtes comme des invités de marque, dans une atmosphère d’intimité et de confidentialité absolues.', true, false, NULL, 0, NULL, '#1a1205', '#C09840', false, true, true, false)
INSERT INTO public.chambres (id, chateau_id, nom, description, superficie, capacite, prix_cents, image, equipements, pricing_rules, min_stay_nights, max_stay_nights, cleaning_fee_cents, ordre) VALUES
  ('e2a610dd-952c-51e1-81b6-c10daca53473', '1835a34d-9680-5a79-8eb4-313e3932c782', 'Chambre Fouquet', 'Suite d''apparat dans l''aile nord, mobilier Louis XIV d''origine, vue sur les jardins Le Nôtre et le Grand Canal.', '45 m²', 2, 38000, 'https://images.unsplash.com/photo-1560185127-6a207d4bb8e0?w=800&q=80', ARRAY['Lit baldaquin','Salle de bain marbre','Vue jardins','Petit-déjeuner inclus']::text[], NULL, 1, NULL, 0, 0),
  ('c3528116-867f-52c7-8a8a-d5c60c826037', '1835a34d-9680-5a79-8eb4-313e3932c782', 'Suite Le Brun', 'Ancienne chambre du peintre Charles Le Brun, plafonds peints d''origine, atmosphère d''atelier royal.', '55 m²', 2, 48000, 'https://images.unsplash.com/photo-1560185893-a55cbc8c57e8?w=800&q=80', ARRAY['Plafonds peints XVIIe','Salon privé','Vue cour d''honneur','Champagne à l''arrivée']::text[], NULL, 1, NULL, 0, 1),
  ('2da63265-b363-55ef-8bc1-d6f5dab74988', '1835a34d-9680-5a79-8eb4-313e3932c782', 'Appartement Le Nôtre', 'Appartement de deux pièces donnant directement sur les parterres brodés, le plus grand domaine privé de France.', '80 m²', 4, 68000, 'https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=800&q=80', ARRAY['2 chambres','Terrasse privée','Vue panoramique','Butler dédié']::text[], NULL, 1, NULL, 0, 2),
  ('8502bb82-0473-52ba-8c0b-5570cd053d46', '471c00ee-8b12-5943-8e79-dddf07959a82', 'Chambre des Preux', 'Dans la tour nord, mobilier néo-gothique dessiné par Viollet-le-Duc, vue sur les douves et la forêt de Compiègne.', '38 m²', 2, 29000, 'https://images.unsplash.com/photo-1631049307264-da0ec9d70304?w=800&q=80', ARRAY['Mobilier Viollet-le-Duc','Vue sur douves','Salle de bain pierre','Petit-déjeuner inclus']::text[], NULL, 1, NULL, 0, 0),
  ('4e7156a2-410c-5ad4-8c9d-6e3b8c9f05e1', '471c00ee-8b12-5943-8e79-dddf07959a82', 'Suite Impériale', 'Appartements de Napoléon III entièrement restaurés, tapisseries d''Aubusson, vue sur la cour d''honneur.', '65 m²', 2, 39000, 'https://images.unsplash.com/photo-1560185893-a55cbc8c57e8?w=800&q=80', ARRAY['Tapisseries Aubusson','Salon impérial','Vue cour d''honneur','Champagne Napoléon']::text[], NULL, 1, NULL, 0, 1),
  ('d01bd5fc-1947-5044-81dd-194c2f2f1239', '471c00ee-8b12-5943-8e79-dddf07959a82', 'Tour de Charlemagne', 'Suite circulaire dans la plus haute tour, panorama à 360° sur Pierrefonds et la forêt, escalier à vis privatif.', '50 m²', 2, 45000, 'https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=800&q=80', ARRAY['Vue 360°','Escalier privatif','Lit à baldaquin','Accès remparts']::text[], NULL, 1, NULL, 0, 2),
  ('a043fc0f-7638-5a65-8a60-59faf403164a', 'e2e456fe-231c-54c0-8ae8-18154104e827', 'Stalle Princière', 'Ancienne stalle des pur-sang du Grand Condé, transformée en chambre de caractère, poutres apparentes et box d''origine.', '42 m²', 2, 45000, 'https://images.unsplash.com/photo-1631049307264-da0ec9d70304?w=800&q=80', ARRAY['Architecture XVIIe','Poutres apparentes','Vue cour des écuries','Petit-déjeuner inclus']::text[], NULL, 1, NULL, 0, 0),
  ('5a515f44-55d5-5730-8e02-82423b910309', 'e2e456fe-231c-54c0-8ae8-18154104e827', 'Suite Condé', 'Suite de deux pièces dans l''aile d''honneur, mobilier Empire, vue directe sur les douves et le château.', '70 m²', 2, 62000, 'https://images.unsplash.com/photo-1560185893-a55cbc8c57e8?w=800&q=80', ARRAY['Mobilier Empire','Vue château et douves','Salon privé','Accès musée privé']::text[], NULL, 1, NULL, 0, 1),
  ('76b565bd-be49-5523-87e6-3c4313a7b2db', 'e2e456fe-231c-54c0-8ae8-18154104e827', 'Appartement Aumale', 'Appartement de trois pièces dans les appartements privés du duc, collection de gravures d''origine, terrasse sur les jardins.', '95 m²', 4, 89000, 'https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=800&q=80', ARRAY['3 pièces','Terrasse jardins','Collection gravures','Butler & majordome']::text[], NULL, 1, NULL, 0, 2),
  ('886012d5-dad8-55c3-814e-b7ff7b11b3b5', '1aa33001-b80e-5447-8f00-4d251072be67', 'Chambre François Ier', 'Dans l''aile Renaissance, lambris peints par l''École de Fontainebleau, mobilier XVIe, vue sur la cour Ovale.', '50 m²', 2, 52000, 'https://images.unsplash.com/photo-1631049307264-da0ec9d70304?w=800&q=80', ARRAY['Lambris Renaissance','Vue cour Ovale','Salle de bain marbre','Petit-déjeuner inclus']::text[], NULL, 1, NULL, 0, 0),
  ('9cc70727-ed31-5ebe-8c60-ef1a5d1d2225', '1aa33001-b80e-5447-8f00-4d251072be67', 'Suite Napoléon', 'Appartements de l''Empereur entièrement restaurés, mobilier Empire d''origine, vue sur le Grand Parterre.', '75 m²', 2, 72000, 'https://images.unsplash.com/photo-1560185893-a55cbc8c57e8?w=800&q=80', ARRAY['Mobilier Empire original','Vue Grand Parterre','Salon privé','Accès appartements privés']::text[], NULL, 1, NULL, 0, 1),
  ('9b5f979e-066b-5174-87c6-9c09634e64c8', '1aa33001-b80e-5447-8f00-4d251072be67', 'Appartement Royal', 'Suite de prestige occupant l''angle de l''aile Louis XV, panorama sur la forêt et les jardins anglais.', '110 m²', 4, 98000, 'https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=800&q=80', ARRAY['4 pièces','Vue forêt & jardins','Piano à queue','Butler Royal dédié']::text[], NULL, 1, NULL, 0, 2),
  ('88a36a4e-6f0b-5265-8daf-926c5699d946', '49be38ea-2e0f-5063-840b-ff44680a5654', 'Chambre du Maréchal', 'La chambre d''apparat du maréchal Henri de Saint-Nectaire, inchangée depuis 1635. Baldaquin d''origine, lambris peints, cheminée en pierre de taille. La vue sur les douves et le parc centenaire est celle qu''avait le maréchal lui-même au lever du soleil.', '35 m²', 2, 22000, 'https://images.unsplash.com/photo-1631049307264-da0ec9d70304?w=800&q=80', ARRAY['Mobilier Louis XIII d''origine','Vue douves & parc centenaire','Cheminée pierre de taille','Petit-déjeuner servi en chambre']::text[], NULL, 1, NULL, 0, 0),
  ('c9a41ab9-7e16-5d2c-8568-19ff913290c0', '49be38ea-2e0f-5063-840b-ff44680a5654', 'Suite Sologne', 'La plus belle suite du château, tournée vers les étangs privés et la forêt de pins. Décoration de maison de chasse noble — trophées anciens, bibliothèque du XVIIIe, cheminée en marbre. Le matin, les brumes de Sologne effacent le monde extérieur. C''est exactement pour cela qu''on vient ici.', '55 m²', 2, 29000, 'https://images.unsplash.com/photo-1560185893-a55cbc8c57e8?w=800&q=80', ARRAY['Vue étangs privés & forêt','Bibliothèque XVIIIe','Cheminée marbre','Dîner à la table des propriétaires']::text[], NULL, 1, NULL, 0, 1),
  ('fc6dfc01-8548-5772-8c06-e15164463b83', '49be38ea-2e0f-5063-840b-ff44680a5654', 'Appartement des Communs', 'Dans les communs du XVIIe siècle entièrement restaurés, cet appartement indépendant dispose de son propre jardin clos, d''une entrée privée sur le parc et d''un accès direct aux étangs. Idéal pour un séjour en couple cherchant l''isolement total, ou pour deux couples voyageant ensemble.', '75 m²', 4, 38000, 'https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=800&q=80', ARRAY['Jardin clos privatif','Entrée indépendante','2 chambres & salon','Accès étangs & barque']::text[], NULL, 1, NULL, 0, 2),
  ('c6b228f9-f137-5530-8b71-863014fcd27c', '5b612841-ab26-5cbd-8b8a-deb8607d6dc8', 'Chambre du Vigneron', 'La chambre la plus authentique du château — celle où dormaient les maîtres de chai au XVIIIe siècle. Vue plongeante sur les rangs de vigne du Mâconnais, mobilier bourguignon massif, tomettes anciennes. Le matin, vous vous réveillez avec l''odeur de la pierre et des ceps. Il n''existe pas d''hôtel au monde qui puisse reproduire ça.', '30 m²', 2, 19500, 'https://images.unsplash.com/photo-1631049307264-da0ec9d70304?w=800&q=80', ARRAY['Vue vignes Mâconnais','Mobilier bourguignon XVIIIe','Tomettes d''origine','Dégustation cave incluse']::text[], NULL, 1, NULL, 0, 0),
  ('9356855d-3779-54da-8166-de7ce32ab9c6', '5b612841-ab26-5cbd-8b8a-deb8607d6dc8', 'Suite du Donjon', 'Dormir dans un donjon du XIIe siècle — pas une métaphore, une réalité. Les murs ont un mètre d''épaisseur. Les fenêtres à meneaux d''origine cadrent un panorama sur les vignes, la vallée de la Saône et, par temps clair, les Alpes. Le lit à baldaquin du XVIIe siècle n''a jamais quitté cette pièce. C''est la chambre la plus demandée du château — réservez tôt.', '45 m²', 2, 28000, 'https://images.unsplash.com/photo-1560185893-a55cbc8c57e8?w=800&q=80', ARRAY['Donjon XIIe · murs 1m','Vue Alpes par temps clair','Lit baldaquin XVIIe','Verticale Pierreclos offerte']::text[], NULL, 1, NULL, 0, 1),
  ('ce562fed-71e6-562f-88ff-d7e181d3ecbe', '5b612841-ab26-5cbd-8b8a-deb8607d6dc8', 'Chambre Lamartine', 'Alphonse de Lamartine venait régulièrement à Pierreclos chercher l''inspiration que Paris ne lui donnait plus. Cette chambre est celle qu''il occupait — mobilier romantique d''époque, bibliothèque rassemblant ses œuvres complètes, vue sur la vallée de la Saône que le poète décrivait comme ''la plus douce de France''. Une nuit ici, c''est une nuit dans un poème.', '40 m²', 2, 24000, 'https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=800&q=80', ARRAY['Vue vallée Saône','Bibliothèque Lamartine complète','Mobilier romantique d''époque','Table d''hôtes & vins du domaine']::text[], NULL, 1, NULL, 0, 2),
  ('af5f5068-123d-541b-899c-ab3c1ca46c3e', '35015d71-5591-570c-8023-cc077d981cd4', 'Chambre Charles X', 'Suite junior avec balcon donnant sur le lac et les jardins de lavande. Mobilier Empire d’époque, lit à baldaquin, vue imprenable sur le parc au lever du soleil.', '27 m²', 2, 32000, 'https://cdn.prod.website-files.com/668c039e26d1cccd00445552/67dda2a0db79b0e72bbb5d7a_Chbre-Charles-X-007w.avif', ARRAY['Balcon vue lac','Mobilier Empire','Lit à baldaquin','Jardins de lavande']::text[], NULL, 1, NULL, 0, 0),
  ('fd55a143-cdd3-5f9d-8dd4-56888b0b8ce4', '35015d71-5591-570c-8023-cc077d981cd4', 'Chambre Verte', 'L’une des chambres les plus demandées du château — papiers peints d’époque, lumière du matin sur le parc, silence absolu. L’Anjou à portee de fenêtre.', '30 m²', 2, 29000, 'https://cdn.prod.website-files.com/668c039e26d1cccd00445552/683da70fd2eed5231f812399_Chambre-verte-013w.avif', ARRAY['Vue parc centenaire','Papiers peints anciens','Salle de bain marbre','Petit-déjeuner inclus']::text[], NULL, 1, NULL, 0, 1),
  ('b3c27696-68d5-5a3b-8a2e-f25f9d8e7bad', '35015d71-5591-570c-8023-cc077d981cd4', 'Cabane Lodge', 'Au cœur des bois du parc, à 50 mètres du château. Sauna privé, baignoire, vue sur la forêt. L’expérience la plus insolite des Briottières — une nuit de Robinson en plein Anjou.', '23 m²', 2, 35000, 'https://cdn.prod.website-files.com/668c039e26d1cccd00445552/6853d2f4bf4fe01ed9e59ad5_PXL_20250430_101041102.MP%20(1)%20(1).avif', ARRAY['Sauna privé','Vue forêt','Baignoire','Accès parc 50 ha']::text[], NULL, 1, NULL, 0, 2),
  ('8ec43bf5-4b9c-53e6-8361-d9624bff7f46', 'b9e0f516-d575-5f55-804e-f66187825cd0', 'Suite du Donjon', 'Dormir dans un donjon du XIIIe siècle — murs de pierre épaisse, fenêtres à méneaux, vue sur les douves. L’expérience la plus médiévale que la Normandie puisse offrir. Réserver tôt — il n’y a qu’une seule suite.', '40 m²', 2, 28000, '/bb-donjon.avif', ARRAY['Donjon XIIIe · murs pierre','Vue douves','Salle de bain privée','Petit-déjeuner inclus']::text[], NULL, 1, NULL, 0, 0),
  ('4b35f2d5-3109-5d08-88cf-df8d2cb7cd16', 'b9e0f516-d575-5f55-804e-f66187825cd0', 'La Réserve', 'Dans l’ancienne charreterie entièrement rénovée, un gîte lumineux et contemporain. Décoration soignée, protégée par les anciens ponts-levis. Parfait pour un couple ou une petite famille.', '55 m²', 4, 22000, '/bb-gite.avif', ARRAY['Ancienne charreterie rénovée','Décoration contemporaine','Accès parc 8 ha','Pont-levis privé']::text[], NULL, 1, NULL, 0, 1)
