  ('94d0884f-043a-5c5a-865a-616e272a5656', '1835a34d-9680-5a79-8eb4-313e3932c782', 'activite'::amenity_type, 'Équitation', 'Balade équestre dans le domaine au lever du soleil', '✦', true, NULL, NULL, 4),
