  ('3317aea4-24c5-5324-895f-88b3b29ef402', '471c00ee-8b12-5943-8e79-dddf07959a82', 'activite'::amenity_type, 'Tir à l''arc médiéval', 'Initiation au tir à l''arc dans les douves du château avec maître archer', '✦', true, NULL, NULL, 0),
  ('ca770392-9ec2-5feb-85bb-54e6a059fe07', '471c00ee-8b12-5943-8e79-dddf07959a82', 'activite'::amenity_type, 'Chevauchée en forêt', 'Randonnée équestre dans la forêt de Compiègne, 14 500 hectares de nature royale', '✦', true, NULL, NULL, 1),
  ('9bf5ff8b-0ed8-5456-811d-474db8a0c6e3', '471c00ee-8b12-5943-8e79-dddf07959a82', 'activite'::amenity_type, 'Festin médiéval', 'Banquet servi à la grande table d''apparat, avec troubadours et jongleurs', '✦', true, NULL, NULL, 2),
  ('9bb03442-78cc-5e2a-8ac7-7b3d9684cf37', '471c00ee-8b12-5943-8e79-dddf07959a82', 'activite'::amenity_type, 'Remparts & donjon', 'Visite exclusive des chemins de ronde et du grand donjon au coucher du soleil', '✦', true, NULL, NULL, 3),
  ('1980e905-871c-57c0-8f6b-576c6a4c0200', '471c00ee-8b12-5943-8e79-dddf07959a82', 'activite'::amenity_type, 'Chasse photographique', 'Safari photo en forêt de Compiègne avec guide naturaliste', '✦', true, NULL, NULL, 4),
  ('ce90a0ba-635b-5956-8bd7-8b72890be0cd', '471c00ee-8b12-5943-8e79-dddf07959a82', 'activite'::amenity_type, 'Canoë sur l''Aisne', 'Descente privée sur la rivière Aisne au pied du château', '✦', true, NULL, NULL, 5),
  ('c5d6f228-2194-5ada-8820-2680b89eb694', 'e2e456fe-231c-54c0-8ae8-18154104e827', 'activite'::amenity_type, 'Polo & hippodrome', 'Visite des écuries princières et entraînement matinal des pur-sang', '✦', true, NULL, NULL, 0),
  ('9b163d0d-c150-5d4b-8b10-c29b849ef595', 'e2e456fe-231c-54c0-8ae8-18154104e827', 'activite'::amenity_type, 'Musée Condé', 'Visite privée de la collection : Raphaël, Botticelli, Poussin...', '✦', true, NULL, NULL, 1),
  ('9973c003-3987-5aa5-860e-7e1b0d70ca1e', 'e2e456fe-231c-54c0-8ae8-18154104e827', 'activite'::amenity_type, 'Atelier Crème Chantilly', 'Secrets de la vraie crème Chantilly avec le chef pâtissier du domaine', '✦', true, NULL, NULL, 2),
  ('89426845-1b61-56f5-8768-c887627f1e7a', 'e2e456fe-231c-54c0-8ae8-18154104e827', 'activite'::amenity_type, 'Calèche dans le parc', 'Promenade en calèche d''époque dans les allées et jardins Le Nôtre', '✦', true, NULL, NULL, 3),
  ('f9bdc5be-4854-5f1d-8fd4-d7fe748bb65f', 'e2e456fe-231c-54c0-8ae8-18154104e827', 'activite'::amenity_type, 'Forêt de Chantilly', 'Randonnée guidée dans les 6 300 hectares de forêt domaniale', '✦', true, NULL, NULL, 4),
  ('93644dd9-8cc2-541a-8104-f5833f5f3bfa', 'e2e456fe-231c-54c0-8ae8-18154104e827', 'activite'::amenity_type, 'Fauconnerie', 'Initiation à la fauconnerie avec les rapaces du domaine', '✦', true, NULL, NULL, 5),
  ('3ea2373a-cc8b-559c-8dcb-22f5320f5a32', '1aa33001-b80e-5447-8f00-4d251072be67', 'activite'::amenity_type, 'Escalade sur chaos de grès', 'Initiation sur les fameux chaos de la forêt avec guide certifié', '✦', true, NULL, NULL, 0),
  ('3bc42d6b-85e8-55c0-862e-5b7b1bd9281c', '1aa33001-b80e-5447-8f00-4d251072be67', 'activite'::amenity_type, 'Appartements royaux', 'Visite privée des appartements de François Ier, Henri IV et Napoléon Ier', '✦', true, NULL, NULL, 1),
  ('d9add83d-b6db-5c03-8464-bfbd74cf945d', '1aa33001-b80e-5447-8f00-4d251072be67', 'activite'::amenity_type, 'Spa & rituels royaux', 'Soins inspirés des traditions royales dans le spa du domaine', '✦', true, NULL, NULL, 2),
  ('4bc5e0e8-c488-52a8-89bf-97b0652831c7', '1aa33001-b80e-5447-8f00-4d251072be67', 'activite'::amenity_type, 'Table gastronomique', 'Dîner dans la salle d''État avec accord mets et vins de Bourgogne', '✦', true, NULL, NULL, 3),
  ('870fcd2b-99e1-5877-8b4a-e0e372800d4e', '1aa33001-b80e-5447-8f00-4d251072be67', 'activite'::amenity_type, 'Forêt de Fontainebleau', '25 000 hectares classés — randonnée, VTT, observation de la faune', '✦', true, NULL, NULL, 4),
  ('3c6bc04f-6747-5edc-8df0-f8fa0dff35f8', '1aa33001-b80e-5447-8f00-4d251072be67', 'activite'::amenity_type, 'Atelier École de Fontainebleau', 'Peinture dans les galeries inspiré des maîtres maniéristes italiens', '✦', true, NULL, NULL, 5),
  ('4cf31e7c-93f5-54b2-8118-522705beab54', '49be38ea-2e0f-5063-840b-ff44680a5654', 'activite'::amenity_type, 'Pêche en étang privé', 'Pêche à la carpe et au brochet dans les étangs privés du domaine', '✦', true, NULL, NULL, 0),
  ('74ae42de-3f45-5ed7-8cb7-ce3e1e25c853', '49be38ea-2e0f-5063-840b-ff44680a5654', 'activite'::amenity_type, 'Cuisines d''époque', 'Cours dans les authentiques cuisines du XVIIe siècle avec le chef', '✦', true, NULL, NULL, 1),
  ('b9ad46ef-439b-5ecc-849f-7459bfad74b7', '49be38ea-2e0f-5063-840b-ff44680a5654', 'activite'::amenity_type, 'Soirée au coin du feu', 'Veillée dans le grand salon avec dégustation de vins de Loire', '✦', true, NULL, NULL, 2),
  ('b80d8646-a53c-5c9d-8c30-de2b20a90620', '49be38ea-2e0f-5063-840b-ff44680a5654', 'activite'::amenity_type, 'Promenade en Sologne', 'Balade guidée dans les étangs et forêts avec botaniste', '✦', true, NULL, NULL, 3),
  ('c6796dad-0554-5758-8600-6103ad1dfcfa', '49be38ea-2e0f-5063-840b-ff44680a5654', 'activite'::amenity_type, 'Observation ornithologique', 'Affût photographique à l''aube — hérons, martins-pêcheurs, cigognes', '✦', true, NULL, NULL, 4),
  ('a7cd3da3-de1e-5813-8c15-1972c422e852', '49be38ea-2e0f-5063-840b-ff44680a5654', 'activite'::amenity_type, 'Attelage d''époque', 'Promenade en attelage dans les allées du parc', '✦', true, NULL, NULL, 5),
  ('e673acb8-e8c2-5157-8b24-da9f7b65d28f', '5b612841-ab26-5cbd-8b8a-deb8607d6dc8', 'activite'::amenity_type, 'Dégustation en cave', 'Verticale de 6 millésimes de Mâcon Villages dans la cave du XIIe siècle', '✦', true, NULL, NULL, 0),
  ('9ec53ecd-fad1-5bba-804a-593a60bcd2e4', '5b612841-ab26-5cbd-8b8a-deb8607d6dc8', 'activite'::amenity_type, 'Visite des vignes', 'Promenade entre les ceps avec le vigneron, explication du terroir et des cépages', '✦', true, NULL, NULL, 1),
  ('db264610-8a19-5440-835d-132685d6de9e', '5b612841-ab26-5cbd-8b8a-deb8607d6dc8', 'activite'::amenity_type, 'Table des propriétaires', 'Dîner gastronomique à la table des propriétaires, accords mets et vins du domaine', '✦', true, NULL, NULL, 2),
  ('3a24cddd-4633-56fe-8e1e-b06ec386a1c7', '5b612841-ab26-5cbd-8b8a-deb8607d6dc8', 'activite'::amenity_type, 'Donjon panoramique', 'Montée au donjon médiéval — vue à 360° sur le Mâconnais et les Alpes', '✦', true, NULL, NULL, 3),
  ('9722ad44-e1ae-589e-8b8d-e5e04ea24177', '5b612841-ab26-5cbd-8b8a-deb8607d6dc8', 'activite'::amenity_type, 'Vélo dans les vignes', 'Circuit dans les appellations Pouilly-Fuissé et Saint-Véran', '✦', true, NULL, NULL, 4),
  ('c101cac2-087b-5ddc-84df-8d98f97020d0', '5b612841-ab26-5cbd-8b8a-deb8607d6dc8', 'activite'::amenity_type, 'Sur les pas de Lamartine', 'Circuit culturel dans les villages inspirateurs du poète romantique', '✦', true, NULL, NULL, 5),
  ('f13f773b-bcf7-5c30-8b98-593f4600be8f', '35015d71-5591-570c-8023-cc077d981cd4', 'activite'::amenity_type, 'Dîner aux chandelles', 'Table d’hôtes familiale dressée chaque soir dans la grande salle, à la lueur des chandelles. Cuisine maison, vins de l’Anjou — Savennières, Layon — partagés à la table des propriétaires.', '◆', true, NULL, NULL, 0),
  ('efa5eda3-4f91-5794-88fb-4c4744326600', '35015d71-5591-570c-8023-cc077d981cd4', 'activite'::amenity_type, 'Piscine dans le parc', 'Piscine extérieure nichée au cœur des cinquante hectares de parc à l’anglaise, ouverte aux beaux jours. Une parenthèse silencieuse, loin des bassins d’hôtel.', '✦', true, NULL, NULL, 1),
  ('11430c03-8ca0-5e53-8dc1-4e769552dfc9', '35015d71-5591-570c-8023-cc077d981cd4', 'activite'::amenity_type, 'Tennis, trampoline, vélos', 'Court de tennis privé, trampoline pour enfants, et flotte de vélos à disposition pour explorer les allées du parc et le bocage angevin alentour.', '✦', true, NULL, NULL, 2),
  ('206fe905-1570-50eb-8842-12a25627348a', '35015d71-5591-570c-8023-cc077d981cd4', 'activite'::amenity_type, 'Promenades dans le parc à l’anglaise', 'Cinquante hectares dessinés au XIXe siècle par le paysagiste Châtelain. Allées centenaires, cèdres, étangs et jardins de lavande — un parc qui change à chaque saison.', '✦', true, NULL, NULL, 3),
  ('341d02d8-80fb-5132-8710-460723f57cdd', '35015d71-5591-570c-8023-cc077d981cd4', 'activite'::amenity_type, 'Balade à cheval dans les bois', 'Sortie équestre dans le bocage angevin entourant le domaine, à l’heure où le tourisme dort encore. Accompagnement par un guide équestre local.', '✦', true, NULL, NULL, 4),
  ('998d4102-e842-5134-8ccb-43a2777021df', '35015d71-5591-570c-8023-cc077d981cd4', 'activite'::amenity_type, 'Châteaux de la Loire à proximité', 'Saumur, Brissac, le Plessis-Bourré, Angers — les grands châteaux ligériens à partir de quarante-cinq minutes de route. Les Briottières comme camp de base discret pour les explorer.', '⚜', true, NULL, NULL, 5),
  ('f815bfc2-c784-5357-8e1f-9c842816e287', 'b9e0f516-d575-5f55-804e-f66187825cd0', 'activite'::amenity_type, 'Visite guidée du château', 'Visite menée par Maïté ou Éric de la Fresnaye à travers les pièces habitées, le donjon du XIIIe siècle, les ponts-levis et les douves intégrales. Sept siècles d’histoire d’une seule maison.', '⚜', true, NULL, NULL, 0),
  ('f6661d61-e7c5-5865-85d4-d33ef40204a9', 'b9e0f516-d575-5f55-804e-f66187825cd0', 'activite'::amenity_type, 'Festival médiéval de printemps', 'Rendez-vous annuel autour de Pâques. Reconstitutions historiques, troubadours, banquet médiéval dans la cour du donjon. Le château ouvre exceptionnellement ses jardins le temps d’un week-end.', '★', true, NULL, NULL, 1),
  ('241d004c-5e04-5177-82c7-e24f3cc29e73', 'b9e0f516-d575-5f55-804e-f66187825cd0', 'activite'::amenity_type, 'Son et lumières d’été', 'Mise en scène de l’histoire du Blanc Buisson sur les murs du donjon, plusieurs soirs par été. Sept siècles racontés par la pierre elle-même, depuis Colinet Lecomte jusqu’à aujourd’hui.', '◆', true, NULL, NULL, 2),
  ('fccf2366-d778-5f6d-820a-7ffe2db4bf9d', 'b9e0f516-d575-5f55-804e-f66187825cd0', 'activite'::amenity_type, 'Ateliers d’art de vivre', 'Sessions de cuisine normande, dégustations œnologiques de cidres et calvados, ateliers d’herboristerie au potager. Programme variable selon la saison et les invités du moment.', '◆', true, NULL, NULL, 3),
  ('5c2ae929-3d4e-5292-8920-ab1250329c7c', 'b9e0f516-d575-5f55-804e-f66187825cd0', 'activite'::amenity_type, 'Sylvothérapie au parc classé', 'Marches conscientes parmi les essences rares du parc de huit hectares — chênes pluricentenaires, hêtres, ifs. Le silence du Pays d’Ouche au plus près des arbres.', '✦', true, NULL, NULL, 4),
  ('1725ee3e-e9b8-5e67-84bc-04836bf88afb', 'b9e0f516-d575-5f55-804e-f66187825cd0', 'activite'::amenity_type, 'Enquête médiévale immersive', 'Enquête immersive en costume dans les pièces du château et les douves, le temps d’une nuit. Sur réservation pour groupes privés. Cadre du XIIIe siècle, scénario sur mesure.', '◆', true, NULL, NULL, 5)
