  ('72ae1261-64e7-5c8c-8fc1-b5d9ed2ac251', 'b9e0f516-d575-5f55-804e-f66187825cd0', '2018', 'Ouverture aux séminaires, réceptions et séjours', 5)
INSERT INTO public.chateau_alentours (id, chateau_id, nom, distance, type, icone, description, ordre) VALUES
  ('75eda397-c4d4-5dae-8df1-bceef9cd379e', '1835a34d-9680-5a79-8eb4-313e3932c782', 'Forêt de Fontainebleau', '20 km', 'nature'::alentour_type, '✦', 'Massif forestier de 25 000 hectares classé, célèbre pour ses chaos rocheux et ses sentiers ouverts à la randonnée et à l''escalade.', 0),
  ('6438a10f-8235-5a62-83ab-7e0a2996b77b', '1835a34d-9680-5a79-8eb4-313e3932c782', 'Melun (marché provençal)', '6 km', 'village'::alentour_type, '◆', 'Préfecture de Seine-et-Marne, marché animé plusieurs fois par semaine au cœur de la vieille ville sur la Seine.', 1),
  ('f5b52425-32d9-5a56-8d50-784a00cfa53d', '1835a34d-9680-5a79-8eb4-313e3932c782', 'Château de Fontainebleau', '18 km', 'culture'::alentour_type, '◆', 'Résidence royale habitée pendant huit siècles, classée au patrimoine mondial de l''UNESCO depuis 1981.', 2),
  ('c81efb87-96bc-599b-87b2-22eabb3830f7', '1835a34d-9680-5a79-8eb4-313e3932c782', 'Barbizon (village des peintres)', '25 km', 'culture'::alentour_type, '◆', 'Village des peintres pré-impressionnistes, où Millet et Théodore Rousseau ont vécu et travaillé au XIXe siècle.', 3),
  ('2aef07c9-5579-5447-8392-bbe2ec05990a', '471c00ee-8b12-5943-8e79-dddf07959a82', 'Forêt de Compiègne', '5 km', 'nature'::alentour_type, '✦', 'Massif royal de 14 500 hectares, ancienne réserve de chasse des rois et empereurs, sentiers et clairières ouverts au public.', 0),
  ('f5073ee6-201a-588f-8dbb-79796f89497f', '471c00ee-8b12-5943-8e79-dddf07959a82', 'Compiègne (palais impérial)', '14 km', 'culture'::alentour_type, '◆', 'Résidence d''été des rois de France et de Napoléon III, vaste palais ouvert à la visite et abritant le musée du Second Empire.', 1),
  ('b70741c4-1b9c-59e4-8e65-7fcfbb774fd6', '471c00ee-8b12-5943-8e79-dddf07959a82', 'Clairière de l''Armistice', '12 km', 'patrimoine'::alentour_type, '⚜', 'Lieu de signature de l''Armistice du 11 novembre 1918, mémorial reconstruit après la Seconde Guerre mondiale.', 2),
  ('ac2ca94c-6954-57c6-84aa-dd2c27254c79', '471c00ee-8b12-5943-8e79-dddf07959a82', 'Village de Pierrefonds', '0.5 km', 'village'::alentour_type, '◆', 'Bourg médiéval pittoresque dominé par le château, étapes de promenade autour de l''étang et des halles.', 3),
  ('0a79fa12-4521-5b47-8d2b-65f3563a1011', 'e2e456fe-231c-54c0-8ae8-18154104e827', 'Forêt de Chantilly', '0 km', 'nature'::alentour_type, '✦', 'Forêt domaniale de 6 300 hectares contiguë au château, sentiers, étangs et site classé Natura 2000.', 0),
  ('c08e7a6f-59e6-5d76-815e-82c22bb8696b', 'e2e456fe-231c-54c0-8ae8-18154104e827', 'Senlis (cité médiévale)', '10 km', 'village'::alentour_type, '◆', 'Cité épiscopale aux ruelles pavées, cathédrale gothique du XIIe siècle et remparts gallo-romains préservés.', 1),
  ('c1ad0bac-eec9-5863-8c63-a1f616c90e15', 'e2e456fe-231c-54c0-8ae8-18154104e827', 'Abbaye de Royaumont', '12 km', 'culture'::alentour_type, '◆', 'Abbaye cistercienne fondée par Saint Louis en 1228, aujourd''hui centre culturel et musical international.', 2),
  ('4f4a0761-603f-5860-8468-6228c0c6f2bc', 'e2e456fe-231c-54c0-8ae8-18154104e827', 'Hippodrome de Chantilly', '1 km', 'sport'::alentour_type, '✦', 'L''un des plus prestigieux hippodromes d''Europe, accueille le Prix du Jockey Club et le Prix de Diane chaque année.', 3),
  ('aec1f5e3-cfe9-5250-8db0-1e67dc322af3', '1aa33001-b80e-5447-8f00-4d251072be67', 'Forêt de Fontainebleau', '0 km', 'nature'::alentour_type, '✦', '25 000 hectares de forêt royale classée, paradis des grimpeurs et des randonneurs, à pied du château.', 0),
  ('b3241d14-a2b2-54c9-8f0e-784489fd73e0', '1aa33001-b80e-5447-8f00-4d251072be67', 'Barbizon (village des peintres)', '8 km', 'culture'::alentour_type, '◆', 'Village où vécurent Millet, Rousseau et l''École de Barbizon, mouvement précurseur de l''impressionnisme français.', 1),
  ('15e32b24-22a2-5834-86b9-4badafeace73', '1aa33001-b80e-5447-8f00-4d251072be67', 'Moret-sur-Loing (cité médiévale)', '12 km', 'village'::alentour_type, '◆', 'Cité fortifiée sur le Loing, ancienne place forte royale aux portes ogivales et aux maisons à colombages.', 2),
  ('4431fcf5-1439-5925-8e25-c9398c386867', '1aa33001-b80e-5447-8f00-4d251072be67', 'Vaux-le-Vicomte', '18 km', 'culture'::alentour_type, '◆', 'Chef-d''œuvre du Grand Siècle, modèle direct de Versailles, à dix-huit kilomètres au nord-ouest.', 3),
  ('b1ce79e4-95d9-524a-8541-3d1dc9c240b4', '49be38ea-2e0f-5063-840b-ff44680a5654', 'Forêt de Sologne', '0 km', 'nature'::alentour_type, '✦', 'Pays de bocages et d''étangs, forêts de pins et de chênes, ancienne terre de chasse royale au sud d''Orléans.', 0),
  ('59861f3f-b21b-58bc-8d7e-a4ad14b02720', '49be38ea-2e0f-5063-840b-ff44680a5654', 'Orléans (cathédrale)', '20 km', 'culture'::alentour_type, '◆', 'Capitale historique du Val de Loire, cathédrale Sainte-Croix gothique flamboyant, mémoire de Jeanne d''Arc.', 1),
  ('7c5f0b27-1179-514c-8ba8-da41c034aa25', '49be38ea-2e0f-5063-840b-ff44680a5654', 'Chambord', '35 km', 'culture'::alentour_type, '◆', 'Plus grand château de la Loire, chef-d''œuvre de la Renaissance française commandé par François Ier en 1519.', 2),
  ('67b9758b-bfcc-507a-89e5-e8fa9c6ac7c6', '49be38ea-2e0f-5063-840b-ff44680a5654', 'La Ferté-Saint-Aubin (village)', '2 km', 'village'::alentour_type, '◆', 'Bourg solognot traversé par le Cosson, halles couvertes du XIXe siècle, gare ouverte sur la ligne Paris-Orléans.', 3),
  ('3084b920-c60a-55b8-860a-627f26c46df9', '5b612841-ab26-5cbd-8b8a-deb8607d6dc8', 'Mâcon (vieille ville)', '12 km', 'village'::alentour_type, '◆', 'Préfecture de Saône-et-Loire sur les rives de la Saône, vieille ville aux toits de tuiles romaines et marché couvert animé.', 0),
  ('5baab931-f2b9-508b-8f5b-80d0815b7c3d', '5b612841-ab26-5cbd-8b8a-deb8607d6dc8', 'Cluny (abbaye médiévale)', '15 km', 'culture'::alentour_type, '◆', 'Vestiges de la plus grande abbaye bénédictine d''Europe, fondée en 910, centre rayonnant de la chrétienté médiévale.', 1),
  ('b08e8577-6ff4-5684-86eb-6081048000cb', '5b612841-ab26-5cbd-8b8a-deb8607d6dc8', 'Solutré (roche)', '5 km', 'nature'::alentour_type, '✦', 'Éperon rocheux mythique du Mâconnais, site préhistorique majeur et panorama exceptionnel sur le vignoble.', 2),
  ('f554c69c-7461-56f5-8e11-795c06a04609', '5b612841-ab26-5cbd-8b8a-deb8607d6dc8', 'Pouilly-Fuissé (vignoble)', '8 km', 'gastronomie'::alentour_type, '◆', 'Appellation emblématique du Mâconnais, grands vins blancs de chardonnay sur sols argilo-calcaires.', 3),
  ('9edbe39b-5f99-5e91-80ae-ceb2dd23da8f', '35015d71-5591-570c-8023-cc077d981cd4', 'Château du Plessis-Bourré', '20 min', 'patrimoine'::alentour_type, '⚜', 'L’un des joyaux méconnus de la Loire — intact depuis 1480, ponts-levis, douves et grand appartement Louis XI. L’antééthèse du château-musée : ici, on entre dans l’histoire.', 0),
  ('04b32753-8384-5e0a-8a22-7b377f0a77c2', '35015d71-5591-570c-8023-cc077d981cd4', 'Angers — la tapisserie de l’Apocalypse', '30 min', 'patrimoine'::alentour_type, '◆', 'Chef-d’œuvre du XIVe siècle, la plus grande tapisserie médiévale du monde (104 mètres) conservée dans le château des rois d’Anjou. Incontournable.', 1),
  ('eddfb308-e908-56be-892f-4cae3ac3d5d0', '35015d71-5591-570c-8023-cc077d981cd4', 'Abbaye de Solesmes', '30 min', 'spirituel'::alentour_type, '★', 'Haut lieu du chant grégorien. Les moines bénédictins perpétuent une tradition musicale millénaire. Assister à un office reste une expérience hors du commun.', 2),
  ('a189db74-d88b-56b3-8554-462095378cc9', '35015d71-5591-570c-8023-cc077d981cd4', 'Vignobles de Savenières & Coulée de Serrant', '45 min', 'gastronomie'::alentour_type, '✦', 'L’un des grands blancs secs du monde, issu de chenin blanc. La Coulée de Serrant est l’une des rares AOC mono-propriétaire de France — six hectares, une famille.', 3),
  ('3c18601d-c30d-554a-84fe-b14b959aad52', '35015d71-5591-570c-8023-cc077d981cd4', 'Château du Lude', '35 min', 'patrimoine'::alentour_type, '⚜', 'Château Renaissance habité par la même famille depuis 1750. Leur spectacle Son & Lumière est l’un des plus grands de France — 300 acteurs, 2 000 spectateurs.', 4),
  ('1961b874-33d0-58c2-8ef3-523fc063698e', '35015d71-5591-570c-8023-cc077d981cd4', 'Sarthe à vélo — Anjou bleu', '10 min', 'nature'::alentour_type, '◆', 'Le canal de la Sarthe et ses écluses, les étangs et bocages de l’Anjou bleu. Des circuits vélo depuis les Briottières traversent des paysages que le tourisme n’a pas encore découverts.', 5),
  ('1727dcf3-b316-583c-8041-22325de794cc', 'b9e0f516-d575-5f55-804e-f66187825cd0', 'Abbaye du Bec-Hellouin', '25 min', 'patrimoine'::alentour_type, '⚜', 'L’une des grandes abbayes bénédictines d’Europe, fondée en 1034. Herluin, Lanfranc, Anselme — ses abbés ont formé des archevêques de Canterbury et influencé la pensée médiévale. Toujours habitée par des moines.', 0),
  ('6b1089d8-3054-59cd-8f54-fc6b9b6138bd', 'b9e0f516-d575-5f55-804e-f66187825cd0', 'Giverny — jardins de Monet', '35 min', 'patrimoine'::alentour_type, '◆', 'Le jardin où Claude Monet peignit ses Nénufars. Un lieu de pèlerinage pour les amateurs d’impressionnisme, à voir au printemps quand les iris et les roses sont en fleur.', 1),
  ('373d219a-3c02-54f1-8593-6bbf43d094b5', 'b9e0f516-d575-5f55-804e-f66187825cd0', 'Les Andelys — Château Gaillard', '30 min', 'patrimoine'::alentour_type, '✦', 'La forteresse de Richard Cœur de Lion, construite en un an en 1196 pour défendre la Normandie contre Philippe Auguste. Un panorama exceptionnel sur les méandres de la Seine.', 2),
  ('1eb5600d-5003-5dd2-82b7-692362f7cec0', 'b9e0f516-d575-5f55-804e-f66187825cd0', 'Évreux — cathédrale Notre-Dame', '30 min', 'patrimoine'::alentour_type, '⚜', 'Une des plus belles cathédrales gothiques de Normandie, avec ses vitraux du XIIIe au XVIIe siècle. La ville d’Évreux possède un centre médiéval remarquablement préservé.', 3),
  ('0b4b1374-e45b-5574-87c1-64f4455a78cc', 'b9e0f516-d575-5f55-804e-f66187825cd0', 'Vernón — vieille ville', '30 min', 'nature'::alentour_type, '◆', 'Une halte bucolique sur les bords de Seine, avec son vieux moulin sur pilotis et ses colombages. Point de départ idéal pour rejoindre Giverny à vélo le long de la rivière.', 4),
  ('0ad64dd0-6215-5451-8b23-89649ed8810f', 'b9e0f516-d575-5f55-804e-f66187825cd0', 'Forêt de Breteuil', '15 min', 'nature'::alentour_type, '★', '5 000 hectares de hêtres et de chênes au cœur du Pays d’Ouche. Sentiers de randonnée, étangs de pêche, silence absolu. La Normandie intérieure à son meilleur.', 5)
